package kyber

import (
	"bytes"
	"encoding/hex"
	"fmt"
	"github.com/Deeptiman/forgekey/go/src/sha3"
	"github.com/stretchr/testify/assert"
	"strings"
	"testing"
)

func mustHex(s string) []byte {
	b, err := hex.DecodeString(strings.TrimPrefix(s, "0x"))
	if err != nil {
		panic(err)
	}
	return b
}

func TestMLKEM_KAT(t *testing.T) {
	z := mustHex("84CC9121AE56FBF39E67ADBD83AD2D3E3BB80843645206BDD9F2F629E3CC49B7")
	d := mustHex("2CB843A02EF02EE109305F39119FABF49AB90A57FFECB3A0E75E179450F52761")

	Ek := mustHex("")
	Dk := mustHex("")

	Ekk := mustHex("")
	m := mustHex("6FF02E1DC7FD911BEEE0C692C8BD100C3E5C48964D31DF92994218E80664A6CA")

	ct1 := mustHex("")
	ss1 := mustHex("0BF323338D6F0A21D5514B673CD10B714CE6E36F35BCD1BF544196368EE51A13")

	pkKEM := mustHex("")
	c := mustHex("")
	k := mustHex("DF462AD68F1EC8972ED9B02D6DE0604BDEC75720E050497351E6EC933E71F882")

	var seed [64]byte
	copy(seed[:], d)
	copy(seed[32:], z)

	for _, l := range []Level{Level512} {
		t.Run(l.String(), func(t *testing.T) {
			p := ParamsFor(l)
			pk, sk := p.GenerateKEMKeyPair(seed[:])

			ek := p.UnPackPublicKey(Ek)
			dk := p.UnPackPrivateKey(Dk)

			assert.Equal(t, pk.pk.T, ek.T)
			assert.Equal(t, sk.sk.V, dk.V)

			ekk := p.UnPackPublicKey(Ekk)
			var ct, ss []byte
			ct = make([]byte, 768)
			ss = make([]byte, 32)
			pk.pk = ekk
			h := sha3.New256()
			h.Write(Ekk)
			h.Read(pk.hpk[:])
			fmt.Println("pk = [hpk] : ", pk.hpk)

			pk.Encapsulate(&p, ct, ss, m)

			assert.Equal(t, ct1, ct)
			assert.Equal(t, ss1, ss)

			dk1 := p.UnPackPrivateKey(pkKEM[:p.PrivateKeySize])
			pkKEM = pkKEM[p.PrivateKeySize:]
			ek1 := p.UnPackPublicKey(pkKEM[:p.PublicKeySize])
			var hpk [32]byte
			h = sha3.New256()
			h.Write(pkKEM[:p.PublicKeySize])
			h.Read(hpk[:])
			pkKEM = pkKEM[p.PublicKeySize:]

			dk2 := &PrivateKeyKEM{}
			dk2.sk = dk1
			dk2.pk = ek1
			copy(dk2.hpk[:], pkKEM[:32])
			copy(dk2.z[:], pkKEM[32:])

			if !bytes.Equal(hpk[:], dk2.hpk[:]) {
				t.Fatal("invalid public key")
			}

			p.Sk = *dk2.sk
			p.Pk = *dk2.pk

			ss2 := make([]byte, 32)
			dk2.Decapsulate(&p, ss2, c)
			assert.Equal(t, hex.EncodeToString(k), hex.EncodeToString(ss2))
		})
	}
}
